import { useEffect, useRef } from 'react';

// â”€â”€ CUSTOM CURSOR â”€â”€
export const useCursor = () => {
  useEffect(() => {
    const dot  = document.querySelector('.cursor-dot');
    const ring = document.querySelector('.cursor-ring');
    if (!dot || !ring) return;

    const move = (e) => {
      dot.style.left  = e.clientX + 'px';
      dot.style.top   = e.clientY + 'px';
      ring.style.left = e.clientX + 'px';
      ring.style.top  = e.clientY + 'px';
    };

    const addHover = () => ring.classList.add('hovered');
    const remHover = () => ring.classList.remove('hovered');

    window.addEventListener('mousemove', move);
    document.querySelectorAll('a,button,.card').forEach(el => {
      el.addEventListener('mouseenter', addHover);
      el.addEventListener('mouseleave', remHover);
    });

    return () => window.removeEventListener('mousemove', move);
  }, []);
};

// â”€â”€ SCROLL REVEAL â”€â”€
export const useScrollReveal = () => {
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            entry.target.classList.add('revealed');
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.12 }
    );

    document.querySelectorAll('.reveal').forEach(el => observer.observe(el));
    return () => observer.disconnect();
  });
};

// â”€â”€ TYPEWRITER â”€â”€
export const useTypewriter = (words, speed = 100, pause = 1800) => {
  const el = useRef(null);

  useEffect(() => {
    if (!el.current) return;
    let wordIdx = 0, charIdx = 0, deleting = false;
    let timer;

    const tick = () => {
      const word = words[wordIdx];
      if (!deleting) {
        el.current.textContent = word.slice(0, ++charIdx);
        if (charIdx === word.length) {
          deleting = true;
          timer = setTimeout(tick, pause);
          return;
        }
      } else {
        el.current.textContent = word.slice(0, --charIdx);
        if (charIdx === 0) {
          deleting = false;
          wordIdx = (wordIdx + 1) % words.length;
        }
      }
      timer = setTimeout(tick, deleting ? speed / 2 : speed);
    };

    timer = setTimeout(tick, speed);
    return () => clearTimeout(timer);
  }, [words, speed, pause]);

  return el;
};
